<?php namespace App\Http\Controllers\Api\Admin; use App\Http\Controllers\Controller; use App\Models\User; use Illuminate\Http\Request; class AdminUserController extends Controller { public function index() { return User::latest()->paginate(20); } public function update(Request $request, User $user) { $user->update($request->all()); return $user; } public function destroy(User $user) { $user->delete(); return response()->noContent(); } }